parameters.jsCode:
const claudeResp = $input.first().json;
const copyText = claudeResp.content[0].text.trim();

let copy;
try {
  const jsonMatch = copyText.match(/\{[\s\S]*\}/);
  copy = JSON.parse(jsonMatch ? jsonMatch[0] : copyText);
} catch(e) {
  copy = { instagram_caption: copyText, facebook_caption: copyText, twitter_text: copyText, hashtags_comment: '' };
}

const imageData = $('Extraer URL imagen').item.json;

return [{
  json: {
    content_id: imageData.content_id,
    image_url: imageData.image_url,
    platforms: imageData.platforms,
    scheduled_date: imageData.scheduled_date,
    scheduled_time: imageData.scheduled_time,
    content_type: 'image',
    copy: copy,
    hashtags: imageData.hashtags,
    ready_to_publish: true
  }
}];
